  "pageId": "additional-maths:7-3-solving-exponential-equations",
  "pageName": "7.3 Solving Exponential Equations",
  "source": "mcq",
  "type": "mcq",
  "marks": 1,
  "question": "For \\( a^x = b \\) with \\( a > 1 \\) and \\( b > 1 \\), the solution \\( x \\) is:",
